
.map-panel {
  width: 100%;
  max-width: 800px;
  padding: 20px;
  background: rgba(0, 0, 0, 0.9);
  border: 2px solid #d4af37;
  border-radius: 8px;
}

.map-header {
  text-align: center;
  margin-bottom: 20px;

  h2 {
    color: #d4af37;
    font-size: 24px;
    margin: 0;
  }
}

.area-card {
  padding: 15px;
  background: rgba(0, 0, 0, 0.6);
  border: 2px solid #666666;
  border-radius: 4px;
  margin-bottom: 10px;
  cursor: pointer;
  transition: all 0.3s ease;

  &:hover {
    border-color: #d4af37;
    transform: translateY(-2px);
  }

  &.current {
    border-color: #ffd700;
    cursor: default;
  }
}

.area-name {
  font-size: 18px;
  font-weight: bold;
  color: #ffffff;
  margin-bottom: 8px;
}

.area-description {
  color: #cccccc;
  font-size: 14px;
}
