
@import '../styles/global.scss';

.dialogue-box {
  position: fixed;
  bottom: calc($spacing-lg + 50px + $spacing-md); // 为底部按钮留出空间（按钮高度 + 间距）
  left: 50%;
  transform: translateX(-50%);
  width: calc(100% - 120px); // 为左右两侧按钮留出空间
  max-width: 800px;
  min-height: 120px;
  max-height: 33vh; // 最大高度为页面的三分之一
  background: $color-bg-overlay;
  border: 2px solid $color-border-gold;
  border-radius: $border-radius-lg;
  padding: $spacing-lg;
  z-index: $z-index-dialogue;
  box-shadow: $shadow-lg, $shadow-gold;
  cursor: pointer;
  transition: all $transition-base;
  display: flex;
  flex-direction: column;

  // 移动端适配
  @include mobile {
    bottom: calc($spacing-sm + 36px + $spacing-xs); // 移动端按钮更小
    width: calc(100% - 80px); // 移动端按钮更小，留出更少空间
    min-height: 100px;
    max-height: 33vh;
    padding: $spacing-md;
    border-width: 1px;
    border-radius: $border-radius-md;
  }

  &:hover {
    border-color: $color-secondary-gold;
    box-shadow:
      $shadow-lg,
      0 0 30px rgba(212, 175, 55, 0.5);
  }
}

.close-button {
  position: absolute;
  top: $spacing-sm;
  right: $spacing-sm;
  width: 28px;
  height: 28px;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.7);
  border: 1px solid $color-border-gold;
  border-radius: $border-radius-sm;
  color: $color-text-gold;
  font-size: $font-size-base;
  cursor: pointer;
  transition: all $transition-fast;
  z-index: 1;

  &:hover {
    background: rgba(244, 67, 54, 0.3);
    border-color: $color-danger;
    color: $color-danger;
  }
}

.dialogue-display {
  width: 100%;
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow-y: auto; // 内容超出时显示滚动条
  min-height: 0; // 允许 flex 子元素缩小
}

.dialogue-content {
  flex: 1;
  min-height: 0; // 允许 flex 子元素缩小
}

.dialogue-text {
  font-size: $font-size-base;
  color: $color-text-primary;
  line-height: 1.8;
  white-space: pre-wrap;
  word-wrap: break-word;

  @include mobile {
    font-size: $font-size-sm;
    line-height: 1.6;
  }
}

.continue-hint {
  margin-top: $spacing-md;
  font-size: $font-size-sm;
  color: $color-text-muted;
  text-align: right;
  font-style: italic;
  animation: pulse 2s ease-in-out infinite;
}

@keyframes pulse {
  0%,
  100% {
    opacity: 0.5;
  }
  50% {
    opacity: 1;
  }
}

.dialogue-placeholder {
  font-size: $font-size-base;
  color: $color-text-secondary;
  text-align: center;
  padding: $spacing-xl 0;

  p {
    margin: $spacing-sm 0;
  }

  .hint {
    font-size: $font-size-sm;
    color: $color-text-muted;
    font-style: italic;
  }
}

.custom-input-container {
  margin-top: $spacing-md;
  padding-top: $spacing-md;
  border-top: 1px solid rgba(212, 175, 55, 0.3);
  display: flex;
  flex-direction: column;
  gap: $spacing-sm;
}

.custom-input-field {
  width: 100%;
  min-height: 80px;
  padding: $spacing-md;
  background: rgba(0, 0, 0, 0.5);
  border: 1px solid $color-border-light;
  border-radius: $border-radius-md;
  color: $color-text-primary;
  font-size: $font-size-base;
  font-family: $font-family-primary;
  resize: vertical;
  outline: none;
  transition: border-color $transition-base;

  // 移动端适配
  @include mobile {
    min-height: 60px;
    padding: $spacing-sm;
    font-size: 16px; // 防止 iOS 自动缩放
  }

  &:focus {
    border-color: $color-primary-gold;
  }

  &::placeholder {
    color: $color-text-muted;
  }
}

.custom-send-button {
  align-self: flex-end;
  padding: $spacing-sm $spacing-lg;
  background: linear-gradient(135deg, $color-primary-gold, $color-dark-gold);
  border: none;
  border-radius: $border-radius-md;
  color: $color-primary-black;
  font-size: $font-size-base;
  font-weight: $font-weight-bold;
  cursor: pointer;
  transition: all $transition-base;
  box-shadow: $shadow-sm;

  // 移动端适配
  @include mobile {
    padding: $spacing-xs $spacing-md;
    font-size: $font-size-sm;
  }

  &:hover:not(:disabled) {
    background: linear-gradient(135deg, $color-secondary-gold, $color-primary-gold);
    box-shadow: $shadow-md, $shadow-gold;
    transform: translateY(-2px);
  }

  &:active:not(:disabled) {
    transform: translateY(0);
    box-shadow: $shadow-sm;
  }

  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
  }
}
