
@import '../styles/global.scss';

.main-interface {
  position: relative;
  width: 100%;
  aspect-ratio: 16 / 9; // 使用 aspect-ratio 控制高度，不使用 vh
  overflow: hidden;
}

// ==================== 层级结构 ====================
.layer {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none; // 默认不接收事件

  // 子元素可以接收事件
  > * {
    pointer-events: auto;
  }
}

.layer-background {
  z-index: $z-index-background;
}

.layer-sprite {
  z-index: $z-index-sprite;
}

.layer-ui {
  z-index: $z-index-ui;
}

.control-panel {
  position: fixed;
  top: calc($spacing-lg + 50px + $spacing-md); // 全屏按钮高度 + 间距
  right: $spacing-lg;
  display: flex;
  flex-direction: column;
  gap: $spacing-sm;
  z-index: $z-index-ui;

  // 移动端适配
  @include mobile {
    top: calc($spacing-sm + 36px + $spacing-xs);
    right: $spacing-sm;
    gap: $spacing-xs;
  }
}

.control-btn {
  width: 40px;
  height: 40px;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(20, 20, 20, 0.9);
  border: 2px solid $color-border-gold;
  border-radius: $border-radius-md;
  color: $color-text-gold;
  font-size: $font-size-xl;
  cursor: pointer;
  transition: all $transition-fast;
  box-shadow: $shadow-md;

  // 移动端适配
  @include mobile {
    width: 32px;
    height: 32px;
    font-size: $font-size-base;
    border-width: 1px;
  }

  &:hover {
    background: rgba(212, 175, 55, 0.2);
    border-color: $color-secondary-gold;
    transform: translateX(-4px);
    box-shadow: $shadow-lg, $shadow-gold;

    @include mobile {
      transform: translateX(-2px);
    }
  }

  &:active {
    transform: translateX(-2px);

    @include mobile {
      transform: translateX(-1px);
    }
  }

  &.active {
    background: rgba(212, 175, 55, 0.3);
    border-color: $color-secondary-gold;
  }
}

.modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(0, 0, 0, 0.8);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: $z-index-modal;
  backdrop-filter: blur(4px);
}

// 通用圆形按钮样式
@mixin round-button {
  width: 50px;
  height: 50px;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(20, 20, 20, 0.9);
  border: 2px solid $color-border-gold;
  border-radius: 50%;
  color: $color-text-gold;
  font-size: $font-size-2xl;
  cursor: pointer;
  transition: all $transition-fast;
  box-shadow: $shadow-lg, $shadow-gold;
  z-index: $z-index-ui;

  // 移动端适配
  @include mobile {
    width: 36px;
    height: 36px;
    font-size: $font-size-lg;
    border-width: 1px;
  }

  &:hover {
    background: rgba(212, 175, 55, 0.2);
    border-color: $color-secondary-gold;
    transform: scale(1.1);
    box-shadow:
      $shadow-lg,
      0 0 30px rgba(212, 175, 55, 0.5);

    @include mobile {
      transform: scale(1.05);
    }
  }

  &:active {
    transform: scale(1.05);

    @include mobile {
      transform: scale(1.02);
    }
  }
}

.ui-toggle-btn {
  @include round-button;
  position: fixed;
  bottom: $spacing-lg;
  left: $spacing-lg;
  z-index: $z-index-controls;

  @include mobile {
    bottom: $spacing-sm;
    left: $spacing-sm;
  }

  // UI 隐藏时半透明
  &.ui-hidden {
    opacity: 0.5;
    background: rgba(20, 20, 20, 0.6);

    &:hover {
      opacity: 0.8;
    }
  }
}

.restore-dialogue-btn {
  @include round-button;
  position: fixed;
  bottom: $spacing-lg;
  right: $spacing-lg;
  z-index: $z-index-controls;

  @include mobile {
    bottom: $spacing-sm;
    right: $spacing-sm;
  }
}

.fullscreen-btn {
  @include round-button;
  position: fixed;
  top: $spacing-lg;
  right: $spacing-lg;

  @include mobile {
    top: $spacing-sm;
    right: $spacing-sm;
  }
}

.plot-review-btn {
  @include round-button;
  position: fixed;
  top: $spacing-lg;
  left: $spacing-lg;
  z-index: $z-index-controls;

  @include mobile {
    top: $spacing-sm;
    left: $spacing-sm;
  }

  &.active {
    background: rgba(212, 175, 55, 0.3);
    border-color: $color-secondary-gold;
    box-shadow: $shadow-gold;
  }
}
