
@import '../styles/global.scss';

.plot-review {
  position: fixed;
  top: 0;
  left: 0;
  width: 400px;
  height: 100%;
  background: linear-gradient(135deg, rgba(20, 20, 30, 0.98), rgba(30, 20, 40, 0.98));
  border-right: 2px solid $color-border-gold;
  box-shadow:
    $shadow-lg,
    4px 0 20px rgba(212, 175, 55, 0.3);
  display: flex;
  flex-direction: column;
  z-index: $z-index-modal;
  animation: slideInLeft 0.3s ease-out;

  // 移动端适配
  @include mobile {
    width: 85%;
    max-width: 320px;
    border-right-width: 1px;
  }
}

@keyframes slideInLeft {
  from {
    transform: translateX(-100%);
    opacity: 0;
  }
  to {
    transform: translateX(0);
    opacity: 1;
  }
}

.plot-review-header {
  padding: $spacing-lg;
  border-bottom: 1px solid rgba(212, 175, 55, 0.3);
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: rgba(0, 0, 0, 0.3);

  @include mobile {
    padding: $spacing-md;
  }
}

.plot-review-title {
  margin: 0;
  font-size: $font-size-xl;
  color: $color-text-gold;
  text-shadow: $text-shadow-gold;
  font-family: $font-family-title;

  @include mobile {
    font-size: $font-size-lg;
  }
}

.close-btn {
  width: 32px;
  height: 32px;
  padding: 0;
  background: rgba(139, 0, 0, 0.3);
  border: 1px solid rgba(220, 20, 60, 0.5);
  border-radius: $border-radius-sm;
  color: $color-danger;
  font-size: $font-size-lg;
  cursor: pointer;
  transition: all $transition-fast;

  &:hover {
    background: rgba(220, 20, 60, 0.3);
    border-color: $color-danger;
    transform: scale(1.1);
  }
}

.plot-review-content {
  flex: 1;
  overflow-y: auto;
  padding: $spacing-md;

  &::-webkit-scrollbar {
    width: 8px;
  }

  &::-webkit-scrollbar-track {
    background: rgba(0, 0, 0, 0.3);
  }

  &::-webkit-scrollbar-thumb {
    background: rgba(212, 175, 55, 0.3);
    border-radius: 4px;

    &:hover {
      background: rgba(212, 175, 55, 0.5);
    }
  }
}

.loading-state,
.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 100%;
  color: $color-text-secondary;
  font-size: $font-size-lg;
  gap: $spacing-md;

  p:first-child {
    font-size: 48px;
    margin: 0;
  }

  p:last-child {
    margin: 0;
  }
}

.loading-spinner {
  width: 40px;
  height: 40px;
  border: 3px solid rgba(212, 175, 55, 0.2);
  border-top-color: $color-border-gold;
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

.messages-list {
  display: flex;
  flex-direction: column;
  gap: $spacing-md;
}

.message-item {
  background: rgba(0, 0, 0, 0.4);
  border: 1px solid rgba(212, 175, 55, 0.2);
  border-radius: $border-radius-md;
  padding: $spacing-md;
  transition: all $transition-fast;

  &:hover {
    border-color: rgba(212, 175, 55, 0.4);
    background: rgba(0, 0, 0, 0.5);
    box-shadow: 0 2px 8px rgba(212, 175, 55, 0.2);
  }

  &.is-user {
    border-left: 3px solid $color-info;
  }

  &.is-system {
    border-left: 3px solid $color-warning;
    background: rgba(255, 193, 7, 0.05);
  }
}

.message-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: $spacing-sm;
  padding-bottom: $spacing-xs;
  border-bottom: 1px solid rgba(212, 175, 55, 0.2);
}

.message-name {
  font-weight: bold;
  color: $color-text-gold;
  font-size: $font-size-base;
}

.message-index {
  font-size: $font-size-sm;
  color: $color-text-secondary;
  font-family: monospace;
}

.message-content {
  color: $color-text-primary;
  font-size: $font-size-base;
  line-height: 1.6;
  word-wrap: break-word;
  white-space: pre-wrap;
}

.plot-review-footer {
  padding: $spacing-md;
  border-top: 1px solid rgba(212, 175, 55, 0.3);
  display: flex;
  gap: $spacing-sm;
  background: rgba(0, 0, 0, 0.3);
}

.action-btn {
  flex: 1;
  padding: $spacing-sm $spacing-md;
  background: rgba(20, 20, 20, 0.8);
  border: 1px solid $color-border-gold;
  border-radius: $border-radius-sm;
  color: $color-text-gold;
  font-size: $font-size-sm;
  cursor: pointer;
  transition: all $transition-fast;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;

  span:first-child {
    font-size: $font-size-lg;
  }

  &:hover {
    background: rgba(212, 175, 55, 0.2);
    border-color: $color-secondary-gold;
    transform: translateY(-2px);
    box-shadow: 0 4px 8px rgba(212, 175, 55, 0.3);
  }

  &:active {
    transform: translateY(0);
  }
}
