
@import '../styles/global.scss';

.interaction-room {
  width: 100%;
  aspect-ratio: 16 / 9;
  background: $color-bg-card;
  border: 2px solid $color-border-gold;
  border-radius: $border-radius-lg;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

// ==================== NPC 选择界面 ====================
.npc-selection-view {
  display: flex;
  flex-direction: column;
  width: 100%;
  padding: $spacing-lg;
  overflow-y: auto;
}

.selection-header {
  text-align: center;
  margin-bottom: $spacing-lg;
  padding-bottom: $spacing-md;
  border-bottom: 1px solid $color-border-dark;
}

.selection-title {
  font-size: $font-size-2xl;
  font-weight: $font-weight-bold;
  color: $color-text-gold;
  margin-bottom: $spacing-xs;
  text-shadow: 0 0 10px rgba(212, 175, 55, 0.5);
}

.selection-subtitle {
  font-size: $font-size-sm;
  color: $color-text-secondary;
}

.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: $spacing-2xl;
  text-align: center;
}

.empty-text {
  font-size: $font-size-lg;
  color: $color-text-secondary;
  margin-bottom: $spacing-sm;
}

.empty-hint {
  font-size: $font-size-sm;
  color: $color-text-muted;
}

.npc-list {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
  gap: $spacing-md;
  margin-bottom: $spacing-lg;
}

.npc-card {
  display: flex;
  align-items: center;
  gap: $spacing-md;
  padding: $spacing-md;
  background: rgba(0, 0, 0, 0.4);
  border: 2px solid $color-border-dark;
  border-radius: $border-radius-md;
  cursor: pointer;
  transition: all $transition-fast;

  &:hover {
    border-color: $color-border-gold;
    transform: translateY(-2px);
    box-shadow: $shadow-gold;
  }

  &.selected {
    border-color: $color-primary-gold;
    background: rgba(212, 175, 55, 0.15);
  }
}

.npc-avatar {
  flex-shrink: 0;
  width: 60px;
  aspect-ratio: 1;
  border-radius: 50%;
  overflow: hidden;
  border: 2px solid $color-border-gold;
}

.avatar-image {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.avatar-placeholder {
  width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(135deg, $color-primary-gold, $color-secondary-gold);
  color: $color-primary-black;
  font-size: $font-size-xl;
  font-weight: $font-weight-bold;
}

.npc-info {
  flex: 1;
  min-width: 0;
}

.npc-name {
  font-size: $font-size-base;
  font-weight: $font-weight-bold;
  color: $color-text-gold;
  margin-bottom: $spacing-xs;
}

.npc-occupation {
  font-size: $font-size-sm;
  color: $color-text-secondary;
  margin-bottom: $spacing-xs;
}

.npc-stats {
  display: flex;
  gap: $spacing-sm;
  align-items: center;
}

.stat-item {
  font-size: $font-size-xs;
  color: $color-text-muted;
}

.important-badge {
  padding: 2px $spacing-xs;
  background: rgba(212, 175, 55, 0.2);
  border: 1px solid $color-border-gold;
  border-radius: $border-radius-sm;
  font-size: $font-size-xs;
  color: $color-text-gold;
}

.selection-indicator {
  flex-shrink: 0;
}

.checkbox {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 24px;
  height: 24px;
  border: 2px solid $color-border-dark;
  border-radius: $border-radius-sm;
  color: transparent;
  transition: all $transition-fast;

  &.checked {
    background: $color-primary-gold;
    border-color: $color-primary-gold;
    color: $color-primary-black;
  }
}

.selection-actions {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: $spacing-md;
  background: rgba(0, 0, 0, 0.3);
  border-radius: $border-radius-md;
  border: 1px solid $color-border-dark;
}

.selection-info {
  display: flex;
  flex-direction: column;
  gap: $spacing-xs;
}

.info-text {
  font-size: $font-size-sm;
  color: $color-text-secondary;
}

.mode-hint {
  font-size: $font-size-xs;
  color: $color-text-gold;
  font-weight: $font-weight-medium;
}

.btn-enter {
  padding: $spacing-sm $spacing-xl;
  background: linear-gradient(135deg, $color-primary-gold, $color-secondary-gold);
  border: none;
  border-radius: $border-radius-sm;
  color: $color-primary-black;
  font-size: $font-size-base;
  font-weight: $font-weight-bold;
  cursor: pointer;
  transition: all $transition-fast;

  &:hover:not(:disabled) {
    transform: translateY(-2px);
    box-shadow: $shadow-gold;
  }

  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
  }
}

// ==================== 聊天室界面 ====================
.chat-room-view {
  display: flex;
  flex-direction: column;
  width: 100%;
  overflow: hidden;
}

.chat-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: $spacing-md $spacing-lg;
  background: rgba(0, 0, 0, 0.5);
  border-bottom: 1px solid $color-border-dark;
}

.header-left {
  display: flex;
  align-items: center;
  gap: $spacing-md;
}

.room-title {
  font-size: $font-size-lg;
  font-weight: $font-weight-bold;
  color: $color-text-gold;
}

.participants {
  display: flex;
  gap: $spacing-xs;
  flex-wrap: wrap;
}

.participant-tag {
  padding: $spacing-xs $spacing-sm;
  background: rgba(212, 175, 55, 0.2);
  border: 1px solid $color-border-gold;
  border-radius: $border-radius-sm;
  font-size: $font-size-xs;
  color: $color-text-gold;
}

.header-actions {
  display: flex;
  gap: $spacing-sm;
}

.btn-clear,
.btn-exit {
  padding: $spacing-xs $spacing-md;
  border: 1px solid $color-border-dark;
  border-radius: $border-radius-sm;
  font-size: $font-size-sm;
  cursor: pointer;
  transition: all $transition-fast;
}

.btn-clear {
  background: rgba(255, 152, 0, 0.2);
  color: #ff9800;
  border-color: #ff9800;

  &:hover {
    background: rgba(255, 152, 0, 0.3);
  }
}

.btn-exit {
  background: rgba(244, 67, 54, 0.2);
  color: $color-danger;
  border-color: $color-danger;

  &:hover {
    background: rgba(244, 67, 54, 0.3);
  }
}

.chat-content {
  flex: 1;
  overflow-y: auto;
  padding: $spacing-md;
  background: rgba(0, 0, 0, 0.2);
}

.empty-chat {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 100%;
  text-align: center;
}

.messages-list {
  display: flex;
  flex-direction: column;
  gap: $spacing-md;
}

.message-item {
  display: flex;
  flex-direction: column;
  gap: $spacing-xs;
  padding: $spacing-sm $spacing-md;
  border-radius: $border-radius-md;
  max-width: 80%;
  animation: fadeIn 0.3s ease-in-out;

  &.user-message {
    align-self: flex-end;
    background: rgba(33, 150, 243, 0.2);
    border: 1px solid rgba(33, 150, 243, 0.4);
  }

  &.npc-message {
    align-self: flex-start;
    background: rgba(76, 175, 80, 0.2);
    border: 1px solid rgba(76, 175, 80, 0.4);
  }

  &.streaming {
    opacity: 0.8;
  }
}

@keyframes fadeIn {
  from {
    opacity: 0;
    transform: translateY(10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.message-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: $spacing-sm;
}

.message-speaker {
  font-size: $font-size-sm;
  font-weight: $font-weight-bold;
  color: $color-text-gold;
}

.message-time {
  font-size: $font-size-xs;
  color: $color-text-muted;
}

.streaming-indicator {
  font-size: $font-size-xs;
  color: $color-text-gold;
  animation: pulse 1.5s ease-in-out infinite;
}

@keyframes pulse {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.5;
  }
}

.message-content {
  font-size: $font-size-sm;
  color: $color-text-primary;
  line-height: 1.5;
  white-space: pre-wrap;
  word-wrap: break-word;
}

.chat-input-area {
  padding: $spacing-md;
  background: rgba(0, 0, 0, 0.4);
  border-top: 1px solid $color-border-dark;
}

.chat-input {
  width: 100%;
  padding: $spacing-sm;
  background: rgba(0, 0, 0, 0.5);
  border: 1px solid $color-border-dark;
  border-radius: $border-radius-sm;
  color: $color-text-primary;
  font-size: $font-size-sm;
  font-family: $font-family-primary;
  resize: none;
  transition: border-color $transition-fast;

  &:focus {
    outline: none;
    border-color: $color-primary-gold;
  }

  &::placeholder {
    color: $color-text-muted;
  }
}

.input-actions {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-top: $spacing-sm;
}

.input-hint {
  font-size: $font-size-xs;
  color: $color-text-muted;
}

.btn-send {
  display: flex;
  align-items: center;
  gap: $spacing-xs;
  padding: $spacing-sm $spacing-lg;
  background: linear-gradient(135deg, $color-primary-gold, $color-secondary-gold);
  border: none;
  border-radius: $border-radius-sm;
  color: $color-primary-black;
  font-size: $font-size-sm;
  font-weight: $font-weight-bold;
  cursor: pointer;
  transition: all $transition-fast;

  &:hover:not(:disabled) {
    transform: translateY(-1px);
    box-shadow: $shadow-gold;
  }

  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
  }
}

.send-icon {
  font-size: $font-size-base;
}

// ==================== 浮动退出按钮（右上角） ====================
.floating-exit-btn-top {
  position: fixed;
  top: $spacing-lg;
  right: $spacing-lg;
  width: 50px;
  height: 50px;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(244, 67, 54, 0.9);
  border: 2px solid $color-danger;
  border-radius: 50%;
  color: white;
  font-size: $font-size-2xl;
  font-weight: $font-weight-bold;
  cursor: pointer;
  transition: all $transition-fast;
  box-shadow: $shadow-lg;
  z-index: 10000; // 确保在最上层

  &:hover {
    background: rgba(244, 67, 54, 1);
    transform: scale(1.1);
    box-shadow:
      $shadow-lg,
      0 0 20px rgba(244, 67, 54, 0.6);
  }

  &:active {
    transform: scale(1.05);
  }
}
