
@import '../styles/global.scss';

.dice-roller {
  width: 100%;
  max-width: 400px;
  padding: $spacing-lg;
  background: $color-bg-overlay;
  border: 2px solid $color-border-gold;
  border-radius: $border-radius-lg;
  box-shadow: $shadow-lg, $shadow-gold;

  &.is-rolling {
    pointer-events: none;
  }
}

.roller-header {
  text-align: center;
  margin-bottom: $spacing-lg;

  h3 {
    color: $color-text-gold;
    font-size: $font-size-2xl;
    margin: 0;
    text-shadow: 0 0 10px rgba(212, 175, 55, 0.5);
  }
}

.skill-selection {
  margin-bottom: $spacing-lg;

  label {
    display: block;
    color: $color-text-gold;
    font-size: $font-size-sm;
    margin-bottom: $spacing-sm;
  }

  select {
    width: 100%;
    padding: $spacing-sm;
    background: rgba(0, 0, 0, 0.6);
    border: 1px solid $color-border-gold;
    border-radius: $border-radius-sm;
    color: $color-text-primary;
    font-size: $font-size-base;
    cursor: pointer;
    transition: all $transition-base;

    &:hover:not(:disabled) {
      border-color: $color-secondary-gold;
      box-shadow: $shadow-gold;
    }

    &:disabled {
      opacity: 0.5;
      cursor: not-allowed;
    }

    option {
      background: $color-primary-black;
      color: $color-text-primary;
    }
  }
}

.roll-actions {
  display: flex;
  gap: $spacing-sm;
  margin-bottom: $spacing-lg;

  button {
    flex: 1;
    padding: $spacing-sm $spacing-lg;
    background: linear-gradient(135deg, $color-primary-gold, $color-dark-gold);
    border: none;
    border-radius: $border-radius-sm;
    color: $color-primary-black;
    font-size: $font-size-base;
    font-weight: $font-weight-bold;
    cursor: pointer;
    transition: all $transition-base;
    text-shadow: 0 1px 2px rgba(255, 255, 255, 0.3);

    &:hover:not(:disabled) {
      background: linear-gradient(135deg, $color-secondary-gold, $color-primary-gold);
      box-shadow: $shadow-md, $shadow-gold;
      transform: translateY(-2px);
    }

    &:active:not(:disabled) {
      transform: translateY(0);
    }

    &:disabled {
      opacity: 0.5;
      cursor: not-allowed;
    }
  }

  .btn-reroll {
    background: linear-gradient(135deg, #888888, #666666);

    &:hover:not(:disabled) {
      background: linear-gradient(135deg, #aaaaaa, #888888);
    }
  }
}

.roll-result {
  padding: $spacing-lg;
  background: rgba(212, 175, 55, 0.1);
  border: 1px solid $color-border-gold;
  border-radius: $border-radius-sm;
}

.dice-display {
  display: flex;
  justify-content: center;
  align-items: center;
  margin-bottom: $spacing-lg;

  .dice-value {
    width: 80px;
    height: 80px;
    display: flex;
    justify-content: center;
    align-items: center;
    background: linear-gradient(135deg, $color-primary-gold, $color-dark-gold);
    border: 3px solid $color-secondary-gold;
    border-radius: $border-radius-md;
    color: $color-primary-black;
    font-size: $font-size-3xl;
    font-weight: $font-weight-bold;
    box-shadow: $shadow-md, $shadow-gold;
    text-shadow: 0 2px 4px rgba(255, 255, 255, 0.3);
  }
}

.result-info {
  text-align: center;
  margin-bottom: $spacing-md;
}

.result-level {
  font-size: $font-size-2xl;
  font-weight: $font-weight-bold;
  margin-bottom: $spacing-sm;
  text-shadow: 0 0 10px currentColor;

  &.result-critical_success {
    color: $color-success;
  }

  &.result-extreme_success {
    color: darken($color-success, 10%);
  }

  &.result-hard_success {
    color: lighten($color-success, 20%);
  }

  &.result-success {
    color: lighten($color-success, 30%);
  }

  &.result-failure {
    color: lighten($color-danger, 30%);
  }

  &.result-critical_failure {
    color: $color-danger;
  }
}

.result-details {
  display: flex;
  justify-content: space-around;
  color: $color-text-gold;
  font-size: $font-size-sm;

  span {
    padding: $spacing-xs $spacing-sm;
    background: rgba(0, 0, 0, 0.5);
    border-radius: $border-radius-sm;
  }
}

.btn-generate {
  width: 100%;
  padding: $spacing-sm $spacing-lg;
  background: linear-gradient(135deg, $color-info, darken($color-info, 10%));
  border: none;
  border-radius: $border-radius-sm;
  color: $color-text-primary;
  font-size: $font-size-base;
  font-weight: $font-weight-bold;
  cursor: pointer;
  transition: all $transition-base;

  &:hover:not(:disabled) {
    background: linear-gradient(135deg, lighten($color-info, 10%), $color-info);
    box-shadow:
      $shadow-md,
      0 0 15px rgba(33, 150, 243, 0.5);
    transform: translateY(-2px);
  }

  &:active:not(:disabled) {
    transform: translateY(0);
  }

  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
  }
}

// 过渡动画
.fade-enter-active,
.fade-leave-active {
  transition: opacity $transition-base;
}

.fade-enter-from,
.fade-leave-to {
  opacity: 0;
}
